mapper.select:
SELECT
    ROUND(AVG(f.aqi_value), 1) AS avgAqi,
    MAX(f.aqi_value) AS maxAqi,
    MIN(f.aqi_value) AS minAqi,
    COUNT(*) AS total
FROM feedback f


        AND f.feedback_time >= #{startDate}


        AND f.feedback_time <= CONCAT(#{endDate}, ' 23:59:59')


        AND f.grid_address IN (
            SELECT gm.grid_address FROM grid_member gm WHERE gm.city_id = #{cityId}
        )


        AND f.grid_address IN (
            SELECT gm.grid_address FROM grid_member gm
            INNER JOIN city c ON gm.city_id = c.id
            WHERE c.province_id = #{provinceId}
        )
